'use client' // Obligatoriu pentru pagini interactive
import { useEffect, useState } from 'react'
import { supabase } from '@/lib/supabase' // Folosește @/ ca să ajungi rapid la folderul lib

export default function PaginaMeniu() {
  const [produse, setProduse] = useState([])

  useEffect(() => {
    async function getProduse() {
      const { data, error } = await supabase.from('produse').select('*')
      if (error) console.log('Eroare:', error)
      else setProduse(data)
    }
    getProduse()
  }, [])

  return (
    <div style={{ padding: '20px', fontFamily: 'sans-serif' }}>
      <h1>Meniu Digital 🍕</h1>
      <hr />
      <ul>
        {produse.map((p) => (
          <li key={p.id}>
            <strong>{p.nume}</strong> - {p.pret} RON
            <p>{p.descriere}</p>
          </li>
        ))}
      </ul>
      {produse.length === 0 && <p>Se încarcă sau nu sunt produse...</p>}
    </div>
  )
}